ps.pstext:
if !IsFeatureImplemented(FEAT_SVE2) && !IsFeatureImplemented(FEAT_SME) then
    EndOfDecode(Decode_UNDEF);
end;
let esize : integer{} = 32;
let n : integer = UInt(Zn);
let m : integer = UInt(Zm);
let da : integer = UInt(Zda);
let index : integer = UInt(i3h::i3l);
let op1_neg : boolean = TRUE;

CheckSVEEnabled();
let VL : integer{} = CurrentVL();
let elements : integer = VL DIV esize;
let eltspersegment : integer = 128 DIV esize;
let op1 : bits(VL) = Z{}(n);
let op2 : bits(VL) = Z{}(m);
let op3 : bits(VL) = Z{}(da);
var result : bits(VL);

for e = 0 to elements-1 do
    let segmentbase : integer = e - (e MOD eltspersegment);
    let s : integer = 2 * segmentbase + index;
    let elem1 : bits(esize DIV 2) = (if op1_neg
                                     then FPNeg{esize DIV 2}(op1[(2*e + 1)*:(esize DIV 2)], FPCR())
                                     else op1[(2*e + 1)*:(esize DIV 2)]);
    let elem2 : bits(esize DIV 2) = op2[s*:(esize DIV 2)];
    let elem3 : bits(esize) = op3[e*:esize];
    result[e*:esize] = FPMulAddH(elem3, elem1, elem2, FPCR());
end;

Z{VL}(da) = result;
